def _self_test() -> None:
    assert len(BANK) == 17, len(BANK)
    ids = [dp.id for dp in BANK]
    assert len(ids) == len(set(ids))
    for dp in BANK:
        assert len(dp.chain) == 3, dp.id
        assert len(dp.explain) >= 150, dp.id
        for q, ref, keys in dp.chain:
            for k in keys:
                assert k.lower() in ref.lower(), (dp.id, k)
    print(f"[PASS] dp_se_version_control_cicd_basics: {len(BANK)}个DeepPoint 自检通过")


if __name__ == "__main__":
    _self_test()
